51	export default function SignupLister() {
52	  const router = useRouter();
53	  const { signIn } = useAuth();
54	  const { show: showToast } = useToast();
55	
56	  const [username, setUsername] = useState('');
57	  const [email, setEmail] = useState('');
58	  const [orgName, setOrgName] = useState('');
59	  const [touched, setTouched] = useState<Partial<Record<FieldKey, boolean>>>({});
60	  const [serverErrors, setServerErrors] = useState<FieldErrors>({});
61	  const [submitting, setSubmitting] = useState(false);
62	
63	  const clientErrors = useMemo(
64	    () => clientValidate({ username, email, orgName }),
65	    [username, email, orgName],
66	  );
67	
68	  // Server-originated inline errors always win; client errors only surface once
69	  // the user has touched a field (avoids yelling before they've typed anything).
70	  const visibleErrors: FieldErrors = {
71	    username: serverErrors.username ?? (touched.username ? clientErrors.username : undefined),
72	    email: serverErrors.email ?? (touched.email ? clientErrors.email : undefined),
73	    orgName: serverErrors.orgName ?? (touched.orgName ? clientErrors.orgName : undefined),
74	  };
75	
76	  const markTouched = useCallback((key: FieldKey) => {
77	    setTouched((t) => (t[key] ? t : { ...t, [key]: true }));
78	  }, []);
79	
80	  const updateField = useCallback(
81	    (key: FieldKey, setter: (s: string) => void) => (next: string) => {
82	      setter(next);
83	      setServerErrors((prev) => (prev[key] ? { ...prev, [key]: undefined } : prev));
84	    },
85	    [],
86	  );
87	
88	  const onSubmit = useCallback(async () => {
89	    setTouched({ username: true, email: true, orgName: true });
90	    const errs = clientValidate({ username, email, orgName });
91	    if (Object.keys(errs).length > 0) return;
92	
93	    setServerErrors({});
94	    setSubmitting(true);
95	    try {
96	      const { data, error } = await supabase.functions.invoke<SignupSuccess>(
97	        'auth-signup-lister',
98	        {
99	          body: {
100	            username: username.trim(),
101	            email: email.trim(),
102	            org_name: orgName.trim(),
103	          },
104	        },
105	      );
106	
107	      if (error) {
108	        const ctx = (error as { context?: unknown }).context;
109	        if (
110	          ctx &&
111	          typeof ctx === 'object' &&
112	          'status' in ctx &&
113	          typeof (ctx as { json?: unknown }).json === 'function'
114	        ) {
115	          const res = ctx as Response;
116	          let body: { error?: string } = {};
117	          try {
118	            body = (await res.clone().json()) as { error?: string };
119	          } catch {
120	            // non-JSON body; fall through to generic toast
121	          }
122	          if (res.status === 409 && body.error === 'USERNAME_TAKEN') {
123	            setServerErrors({ username: 'Username already taken' });
124	            return;
125	          }
126	          if (res.status === 409 && body.error === 'EMAIL_TAKEN') {
127	            setServerErrors({ email: 'Email already in use' });
128	            return;
129	          }
130	        }
131	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
132	        return;
133	      }
134	
135	      if (!data) {
136	        showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
137	        return;
138	      }
139	
140	      // The edge function response carries only token + user_id + role. We
141	      // construct the AuthUser row shape client-side; the real timestamps live
142	      // in Postgres and will be read by later queries (profile screen, etc.).
143	      const nowIso = new Date().toISOString();
144	      const nextUser: AuthUser = {
145	        id: data.user_id,
146	        username: username.trim(),
147	        email: email.trim(),
148	        role: 'lister',
149	        created_at: nowIso,
150	        updated_at: nowIso,
151	        deleted_at: null,
152	      };
153	      signIn(data.token, nextUser);
154	      showToast({ message: 'Welcome', variant: 'success' });
155	      router.replace('/(lister)/dashboard');
156	    } catch (err) {
157	      console.error('Lister signup threw', err);
158	      showToast({ message: 'Signup failed. Please try again.', variant: 'error' });
159	    } finally {
160	      setSubmitting(false);
161	    }
162	  }, [username, email, orgName, signIn, showToast, router]);
163	
164	  return (
165	    <SafeAreaView style={styles.container}>
166	      <KeyboardAvoidingView
167	        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
168	        style={styles.flex}
169	      >
170	        <ScrollView
171	          contentContainerStyle={styles.scrollContent}
172	          keyboardShouldPersistTaps="handled"
173	        >
174	          <View style={styles.header}>
175	            <Text style={[textStyles.display, styles.title]}>Company signup</Text>
176	            <Text style={[textStyles.body, styles.subtitle]}>
177	              Pick a handle, tell us who you are, and start posting bounties.
178	            </Text>
179	          </View>
180	
181	          <View style={styles.fields}>
182	            <Field
183	              label="Username"
184	              value={username}
185	              onChange={updateField('username', setUsername)}
186	              onBlur={() => markTouched('username')}
187	              autoCapitalize="none"
188	              autoCorrect={false}
189	              autoComplete="username"
190	              placeholder="acme_media"
191	              error={visibleErrors.username}
192	              testID="lister-signup-username"
193	            />
194	            <Field
195	              label="Email"
196	              value={email}
197	              onChange={updateField('email', setEmail)}
198	              onBlur={() => markTouched('email')}
199	              autoCapitalize="none"
200	              autoCorrect={false}
201	              keyboardType="email-address"
202	              autoComplete="email"
203	              placeholder="hello@acme.co"
204	              error={visibleErrors.email}
205	              testID="lister-signup-email"
206	            />
207	            <Field
208	              label="Company name"
209	              value={orgName}
210	              onChange={updateField('orgName', setOrgName)}
211	              onBlur={() => markTouched('orgName')}
212	              autoCapitalize="words"
213	              autoComplete="organization"
214	              placeholder="Acme Media"
215	              error={visibleErrors.orgName}
216	              testID="lister-signup-orgname"
217	            />
218	          </View>
219	
220	          <ButtonPrimary
221	            label="Finish"
222	            onPress={onSubmit}
223	            loading={submitting}
224	            disabled={submitting}
225	            accessibilityLabel="Finish company signup"
226	            testID="lister-signup-submit"
227	          />
228	        </ScrollView>
229	      </KeyboardAvoidingView>
230	    </SafeAreaView>
231	  );
