1	// Edge function: auth-signup-lister (US-014)
2	//
3	// Contract:
4	//   POST { username: string, email: string, org_name: string, website_url?: string }
5	//     → 200 { token: string, user_id: string, role: 'lister' }
6	//     → 400 { error: 'INVALID_REQUEST' | 'INVALID_JSON' }
7	//     → 409 { error: 'USERNAME_TAKEN' | 'EMAIL_TAKEN' }
8	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' | 'JWT_ERROR' }
9	//
10	// Auth: none. This is how a lister obtains their first JWT, so the endpoint
11	// is verify_jwt=false at the gateway. The handler itself mints the token via
12	// _shared/jwt.ts (HS256, MARKETIFY_JWT_SECRET).
13	//
14	// Atomicity: the users + lister_profiles inserts run inside a single
15	// Postgres transaction via the public.auth_signup_lister RPC (us_014
16	// migration). A failure on the second insert rolls back the first.
17	//
18	// Rate limit: not implemented yet. Spec §5.1 requires per-IP throttling via
19	// a signup_attempts table, which does not exist as of US-014. Tracked in
20	// progress.txt Codebase Patterns as a future-story item.
21	
22	import { createClient } from "npm:@supabase/supabase-js@2";
23	import { signJwt } from "../_shared/jwt.ts";
24	import { corsHeaders } from "../_shared/cors.ts";
25	
26	interface SignupRequest {
27	  username?: unknown;
28	  email?: unknown;
29	  org_name?: unknown;
30	  website_url?: unknown;
31	}
32	
33	function jsonResponse(status: number, body: unknown): Response {
34	  return new Response(JSON.stringify(body), {
35	    status,
36	    headers: { ...corsHeaders, "Content-Type": "application/json" },
37	  });
38	}
39	
40	function isNonEmptyString(value: unknown): value is string {
41	  return typeof value === "string" && value.trim().length > 0;
42	}
43	
44	Deno.serve(async (req) => {
45	  if (req.method === "OPTIONS") {
46	    return new Response(null, { status: 204, headers: corsHeaders });
47	  }
48	  if (req.method !== "POST") {
49	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
50	  }
51	
52	  let body: SignupRequest;
53	  try {
54	    body = await req.json();
55	  } catch {
56	    return jsonResponse(400, { error: "INVALID_JSON" });
57	  }
58	
59	  const username = isNonEmptyString(body.username) ? body.username.trim() : null;
60	  const email = isNonEmptyString(body.email) ? body.email.trim() : null;
61	  const orgName = isNonEmptyString(body.org_name) ? body.org_name.trim() : null;
62	  const websiteUrl = isNonEmptyString(body.website_url)
63	    ? body.website_url.trim()
64	    : null;
65	
66	  if (!username || !email || !orgName) {
67	    return jsonResponse(400, { error: "INVALID_REQUEST" });
68	  }
69	
70	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
71	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
72	  if (!supabaseUrl || !serviceRoleKey) {
73	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
74	  }
75	
76	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
77	    auth: { persistSession: false, autoRefreshToken: false },
78	  });
79	
80	  const { data, error } = await supabase.rpc("auth_signup_lister", {
81	    p_username: username,
82	    p_email: email,
83	    p_org_name: orgName,
84	    p_website_url: websiteUrl,
85	  });
86	
87	  if (error) {
88	    console.error("auth_signup_lister rpc error", error);
89	    return jsonResponse(500, { error: "DB_ERROR" });
90	  }
91	
92	  const result = data as { user_id?: string; error?: string } | null;
93	  if (result?.error === "USERNAME_TAKEN") {
94	    return jsonResponse(409, { error: "USERNAME_TAKEN" });
95	  }
96	  if (result?.error === "EMAIL_TAKEN") {
97	    return jsonResponse(409, { error: "EMAIL_TAKEN" });
98	  }
99	  if (!result?.user_id) {
100	    console.error("auth_signup_lister returned unexpected shape", result);
101	    return jsonResponse(500, { error: "DB_ERROR" });
102	  }
103	
104	  const userId = result.user_id;
105	  const sessionId = crypto.randomUUID();
106	  let token: string;
107	  try {
108	    token = await signJwt({
109	      sub: userId,
110	      role: "lister",
111	      session_id: sessionId,
112	    });
113	  } catch (err) {
114	    console.error("signJwt failed", err);
115	    return jsonResponse(500, { error: "JWT_ERROR" });
116	  }
117	
118	  return jsonResponse(200, { token, user_id: userId, role: "lister" });
119	});
